All three exported functions have no tests.

**Gaps:**
- All 5 format variants for `formatDate`
- Midnight/noon boundary for `formatTime` (12h clock: 0h→12 AM, 12h→12 PM)
- `showSeconds: false` branch
- `showDate: false` branch in `formatDateTime`

```ts
// src/lib/datetime.test.ts
import { describe, it, expect } from 'vitest';
import { formatDate, formatTime, formatDateTime } from '$lib/datetime';

const D = new Date(2026, 4, 9, 15, 4, 9); // 2026-05-09 15:04:09

describe('formatDate', () => {
  it('mdy formats as M/D/Y', () => {
    expect(formatDate(D, 'mdy12')).toBe('5/9/2026');
  });
  it('dmy formats as D/M/Y', () => {
    expect(formatDate(D, 'dmy24')).toBe('9/5/2026');
  });
  it('ymd24 formats as YYYY-MM-DD with zero-padding', () => {
    expect(formatDate(D, 'ymd24')).toBe('2026-05-09');
  });
});

describe('formatTime', () => {
  it('mdy12 produces 12-hour format with AM/PM', () => {
    expect(formatTime(D, 'mdy12')).toBe('3:04:09 PM');
  });
  it('mdy24 produces 24-hour format', () => {
    expect(formatTime(D, 'mdy24')).toBe('15:04:09');
  });
  it('midnight renders as 12:00:00 AM in 12h', () => {
    expect(formatTime(new Date(2026, 0, 1, 0, 0, 0), 'mdy12')).toBe('12:00:00 AM');
  });
  it('noon renders as 12:00:00 PM in 12h', () => {
    expect(formatTime(new Date(2026, 0, 1, 12, 0, 0), 'mdy12')).toBe('12:00:00 PM');
  });
  it('omits seconds when showSeconds is false', () => {
    expect(formatTime(D, 'mdy24', false)).toBe('15:04');
  });
});

describe('formatDateTime', () => {
  it('combines date and time with ·', () => {
    expect(formatDateTime(D, 'mdy12')).toMatch(/5\/9\/2026 · 3:04:09 PM/);
  });
  it('returns time only when showDate is false', () => {
    expect(formatDateTime(D, 'mdy24', { showDate: false })).toBe('15:04:09');
  });
  it('omits seconds when showSeconds is false', () => {
    expect(formatDateTime(D, 'mdy24', { showSeconds: false })).toMatch(/15:04$/);
  });
});
```

