All 5 exported functions untested. The module uses module-level state (`clients` Map), so tests must account for state leakage between cases.

**Gaps:**
- `flagSuspicious` → sets `challengeRequired` to true
- `markVerified` → clears flag, sets `isVerified` to true
- Flag expiry: after `FLAG_WINDOW_MS`, `challengeRequired` returns false
- Verify expiry: after `VERIFY_WINDOW_MS`, `isVerified` returns false
- `getClientKey` falls back through `x-forwarded-for` → `getClientAddress()` → `'unknown'`
- State TTL pruning (stale entries removed)

```ts
// src/lib/server/security.test.ts
import { describe, it, expect, vi, beforeEach } from 'vitest';

// Reset module state between tests by re-importing each time
// OR use vi.useFakeTimers() to control Date.now()

describe('flagSuspicious / challengeRequired', () => {
  it('makes challengeRequired true immediately after flagging', () => {
    // import { flagSuspicious, challengeRequired } from './security';
    flagSuspicious('1.2.3.4');
    expect(challengeRequired('1.2.3.4')).toBe(true);
  });

  it('challengeRequired is false after the flag window expires', () => {
    vi.useFakeTimers();
    flagSuspicious('1.2.3.5');
    vi.advanceTimersByTime(5 * 60_000 + 1);
    expect(challengeRequired('1.2.3.5')).toBe(false);
    vi.useRealTimers();
  });
});

describe('markVerified / isVerified', () => {
  it('isVerified is true after marking verified', () => {
    flagSuspicious('2.3.4.5');
    markVerified('2.3.4.5');
    expect(isVerified('2.3.4.5')).toBe(true);
    expect(challengeRequired('2.3.4.5')).toBe(false);
  });

  it('isVerified becomes false after verify window expires', () => {
    vi.useFakeTimers();
    markVerified('3.4.5.6');
    vi.advanceTimersByTime(15 * 60_000 + 1);
    expect(isVerified('3.4.5.6')).toBe(false);
    vi.useRealTimers();
  });
});

describe('getClientKey', () => {
  it('prefers x-forwarded-for first IP', () => {
    const event = {
      request: { headers: { get: (h: string) => h === 'x-forwarded-for' ? '10.0.0.1, 10.0.0.2' : null } },
      getClientAddress: () => '10.0.0.9',
    } as any;
    expect(getClientKey(event)).toBe('10.0.0.1');
  });

  it('falls back to getClientAddress when no forwarded header', () => {
    const event = {
      request: { headers: { get: () => null } },
      getClientAddress: () => '10.0.0.9',
    } as any;
    expect(getClientKey(event)).toBe('10.0.0.9');
  });

  it("returns 'unknown' when both are empty", () => {
    const event = {
      request: { headers: { get: () => null } },
      getClientAddress: () => '',
    } as any;
    expect(getClientKey(event)).toBe('unknown');
  });
});
